#include<bits/stdc++.h>
using namespace std;
int a[11],dp[1000010],w[10001];
int sum;
int main()
{
    while(scanf("%d%d%d%d%d%d",&a[1],&a[2],&a[3],&a[4],&a[5],&a[6])==6)
    {
        if((a[1]+a[3]+a[5])%2!=0)
        {
            printf("Can't\n");
            continue;
        }
        if(a[1]+a[2]+a[3]+a[4]+a[5]+a[6]==0)
        {
            break;
        }
        int tmp=(a[1]+a[2]*2+a[3]*3+a[4]*4+a[5]*5+a[6]*6)/2,m=0;
        for(int i=1;i<=6;i++)
        {
            int base=1;
            while(base<=a[i])
            {
                a[i]-=base;
                w[++m]=base*i;
                base*=2;
            }
            if(a[i]!=0)
            {
                w[++m]=a[i]*i;
            }
        }
        memset(dp,0,sizeof(dp));
        dp[0]=1;
        for(int i=1;i<=m;i++)
        {
            for(int j=tmp;j>=w[i];j--)
            {
                dp[j]|=dp[j-w[i]];
            }
        }
        if(dp[tmp])
        {
            printf("Can\n");
        }
        else
        {
            printf("Can't\n");
        }
    }
    return 0;
}
